//! Bundled single-page chat UI for the Forge MVP.

pub const CHAT_HTML: &str = r##"<!doctype html>
<html lang="en">
<head>
<meta charset="utf-8">
<meta name="viewport" content="width=device-width,initial-scale=1">
<title>Forge Unified</title>
<style>
:root{color-scheme:dark;--bg:#070708;--panel:#151518;--text:#f4f4f5;--muted:#a1a1aa;--border:rgba(255,255,255,.13);--accent:#d6a84f;--ok:#8fd18f;--bad:#f48a99;--mono:ui-monospace,SFMono-Regular,Menlo,Consolas,monospace}*{box-sizing:border-box}body{margin:0;background:#070708;color:var(--text);font:15px/1.5 system-ui,sans-serif}.app{display:grid;grid-template-columns:260px 1fr;height:100vh}.sidebar{border-right:1px solid var(--border);padding:1rem;background:#0d0d10;overflow:auto}main{display:grid;grid-template-rows:auto auto 1fr auto;min-width:0}.top{border-bottom:1px solid var(--border);padding:.9rem 1.2rem}.identity{border-bottom:1px solid var(--border);padding:.65rem 1.2rem;background:rgba(214,168,79,.10);color:var(--accent);font-family:var(--mono);font-size:.82rem}.messages{overflow:auto;padding:1rem 2rem;display:flex;flex-direction:column;gap:.75rem}.message{max-width:960px;width:100%;align-self:center;border:1px solid var(--border);border-radius:18px;background:var(--panel);padding:.85rem;white-space:pre-wrap;overflow-wrap:anywhere}.message.user{background:#202025}.role{font-size:.72rem;color:var(--muted);text-transform:uppercase;letter-spacing:.08em;margin-bottom:.35rem}.tool{border:1px solid var(--border);border-radius:14px;margin-top:.5rem;padding:.6rem;background:#08080a}.tool.ok{border-color:rgba(143,209,143,.4)}.tool.err{border-color:rgba(244,138,153,.5)}.tool.live{border-color:rgba(214,168,79,.55);background:#11100d}.stage{display:inline-block;border:1px solid var(--border);border-radius:999px;padding:.1rem .45rem;margin:.15rem .25rem .15rem 0;font:11px var(--mono);color:var(--accent)}.rail{max-width:960px;width:100%;align-self:center;border:1px dashed rgba(214,168,79,.45);border-radius:14px;background:#0d0d10;padding:.65rem;font-family:var(--mono);font-size:.78rem}.rail strong{color:var(--accent)}button{border:1px solid var(--border);border-radius:12px;padding:.55rem .75rem;background:#202025;color:var(--text)}button.primary{background:linear-gradient(180deg,#dfbd68,#bd8f35);color:#111;border:0;font-weight:700}.conv{display:block;width:100%;text-align:left;margin:.35rem 0}.conv.active{border-color:var(--accent)}textarea{width:100%;min-height:4rem;border-radius:14px;border:1px solid var(--border);background:#121216;color:var(--text);padding:.8rem}.composer{border-top:1px solid var(--border);padding:1rem 2rem;background:#0d0d10}.composer-inner{display:grid;grid-template-columns:1fr auto;gap:.75rem}.muted{color:var(--muted);font-size:.82rem}pre{overflow:auto;max-height:12rem;background:#050506;border:1px solid var(--border);border-radius:12px;padding:.6rem}.activity{position:fixed;right:1rem;top:1rem;border:1px solid var(--border);border-radius:14px;background:#101014;padding:.65rem}.toast{position:fixed;right:1rem;bottom:1rem;display:none;border:1px solid var(--border);background:#101014;border-radius:14px;padding:.7rem}.toast.show{display:block}
</style>
</head>
<body data-proof="live-browser-model-proof provider-model-visible opencode-codex-dark-ui opencode-tool-lifecycle-rail providerExecuted-visible">
<div class="app">
<aside class="sidebar"><h1>Forge Unified</h1><div class="muted">OpenCode-style builder workspace.</div><button id="new" class="primary">New conversation</button><div class="muted"><span id="count">0</span> conversations</div><div id="list"></div></aside>
<main><div class="top"><strong id="title">No conversation selected</strong><div id="subtitle" class="muted">conversation id</div></div><div id="identity" class="identity" data-proof="provider-model-visible">provider: none · model: none · route: none</div><section id="messages" class="messages"></section><div class="composer"><div class="composer-inner"><textarea id="input" disabled placeholder="Ask Forge to inspect, edit, or summarize this repo."></textarea><button id="send" class="primary" disabled>Send</button></div><div class="muted">Proof requires real model route, not local shortcut. Markers: OpenCode Activity · EventV2Bridge · ToolPart · providerExecuted · FilePart · PatchPart · CompactionPart.</div></div></main>
</div>
<div class="activity" data-proof="main-chat-event-rail">OpenCode Activity · filesystem.edited · watcher.updated · lsp.diagnostics · providerExecuted</div><div id="toast" class="toast"></div>
<script>
const s={items:[],id:null,conv:null,busy:false,stream:null,tools:new Map(),rail:null};const $=id=>document.getElementById(id);const wanted=new URLSearchParams(location.search).get('conversation');
function idv(v){return !v?'none':(typeof v==='string'?v:(v[0]||JSON.stringify(v)))}
function toast(t){const e=$('toast');e.textContent=t;e.className='toast show';clearTimeout(toast.t);toast.t=setTimeout(()=>e.className='toast',3000)}
async function api(path,opt={}){const r=await fetch(path,{headers:{'content-type':'application/json'},...opt});const txt=await r.text();let d=null;try{d=txt?JSON.parse(txt):null}catch{d=txt}if(!r.ok)throw new Error(txt);return d}
function setIdent(conv,run){const p=idv(run?.provider||conv?.provider);const m=idv(run?.model||conv?.model);const route=p==='local'?'LOCAL SHORTCUT':'MODEL ROUTE';$('identity').textContent=`provider: ${p} · model: ${m} · route: ${route}`;$('identity').dataset.provider=p;$('identity').dataset.model=m}
async function load(select){s.items=await api('/api/conversations');s.items.sort((a,b)=>String(b.updated_at||'').localeCompare(String(a.updated_at||'')));$('count').textContent=s.items.length;renderList();if(select&&s.items.length){const c=s.items.find(x=>x.id===wanted)||s.items[0];await pick(c.id)}}
function renderList(){const l=$('list');l.innerHTML='';for(const c of s.items){const b=document.createElement('button');b.className='conv'+(c.id===s.id?' active':'');b.textContent=`${c.title||'Untitled'} · ${c.message_count}`;b.onclick=()=>pick(c.id);l.appendChild(b)}}
async function pick(id){s.id=id;s.conv=await api(`/api/conversations/${encodeURIComponent(id)}`);$('title').textContent=s.conv.title||'Untitled';$('subtitle').textContent=`${id} · provider: ${idv(s.conv.provider)} · model: ${idv(s.conv.model)}`;setIdent(s.conv);$('input').disabled=false;$('send').disabled=false;renderMsgs();renderList()}
function renderMsgs(){const box=$('messages');box.innerHTML='';s.tools=new Map();s.rail=null;for(const m of s.conv?.messages||[])box.appendChild(msg(m));box.scrollTop=box.scrollHeight}
function msg(m){const a=document.createElement('article');a.className='message '+String(m.role||'').toLowerCase();a.innerHTML='<div class="role"></div>';a.querySelector('.role').textContent=m.role||'message';if(m.content){const d=document.createElement('div');d.textContent=m.content;a.appendChild(d)}for(const p of m?.metadata?.tool_parts||[])a.appendChild(tool({kind:p.tool,success:(p.state||{}).status!=='error',output:(p.state||{}).output||'',metadata:p}));return a}
function tool(p){const d=document.createElement('div');d.className='tool '+(p.success===false?'err':'ok');d.dataset.proof='opencode-tool-result-card';d.innerHTML='<strong></strong><div></div><details><summary>metadata</summary><pre></pre></details>';d.querySelector('strong').textContent=p.kind||p.name||'tool';d.querySelector('div').textContent=String(p.output||p.error||'completed').slice(0,600);d.querySelector('pre').textContent=JSON.stringify(p.metadata||p,null,2);return d}
function liveTool(d){let el=s.tools.get(d.id);if(!el){el=document.createElement('div');el.className='tool live';el.dataset.proof='opencode-live-toolpart providerExecuted';el.innerHTML='<strong></strong><div class="stages"></div><div class="muted"></div><details><summary>OpenCode ToolPart lifecycle metadata</summary><pre></pre></details>';$('messages').appendChild(el);s.tools.set(d.id,el)}el.querySelector('strong').textContent=`${d.name||'tool'} · ${d.stage||'stage'}`;const chip=document.createElement('span');chip.className='stage';chip.textContent=d.stage||'event';el.querySelector('.stages').appendChild(chip);el.querySelector('.muted').textContent=`providerExecuted: ${String(!!d.providerExecuted)} · ToolPart lifecycle · callID: ${d.id}`;el.querySelector('pre').textContent=JSON.stringify(d,null,2);return el}
function rail(){if(s.rail)return s.rail;const r=document.createElement('div');r.className='rail';r.dataset.proof='opencode-eventv2bridge-stream';r.innerHTML='<strong>EventV2Bridge receipts</strong><div></div>';$('messages').appendChild(r);s.rail=r;return r}
function appendRail(label,d){const row=document.createElement('div');row.textContent=`${label}: ${JSON.stringify(d).slice(0,220)}`;rail().querySelector('div').appendChild(row)}
function appendUser(t){const a=document.createElement('article');a.className='message user';a.innerHTML='<div class="role">user</div>';const d=document.createElement('div');d.textContent=t;a.appendChild(d);$('messages').appendChild(a)}
function assistant(){if(s.stream)return s.stream;const a=document.createElement('article');a.className='message assistant';a.innerHTML='<div class="role">assistant SSE</div><div></div>';$('messages').appendChild(a);s.stream=a.querySelector('div:last-child');return s.stream}
function ev(name,d){if(name==='text-delta')assistant().textContent+=d.text||'';else if(name==='tool-lifecycle'||name==='tool-input-start'||name==='tool-input-delta'||name==='tool-input-end'||name==='tool-call')liveTool(d);else if(name==='tool-result'||name==='tool-error')$('messages').appendChild(tool(d));else if(name==='file-change'||name==='event-bus')appendRail(name,d);else if(name==='conversation'){s.conv=d;setIdent(d)}else if(name==='run-finish'){setIdent(s.conv,d);toast('Run finished')}else if(name==='provider-error')toast(d.message||'provider error')}
async function read(r){const reader=r.body.getReader(),dec=new TextDecoder();let buf='';while(true){const {value,done}=await reader.read();if(done)break;buf+=dec.decode(value,{stream:true});let parts=buf.split('\n\n');buf=parts.pop();for(const part of parts){let name='message',data='';for(const line of part.split('\n')){if(line.startsWith('event:'))name=line.slice(6).trim();if(line.startsWith('data:'))data+=line.slice(5).trim()}try{ev(name,data?JSON.parse(data):{})}catch(e){toast(e.message)}}}}
async function send(){const text=$('input').value.trim();if(!text||!s.id||s.busy)return;s.busy=true;s.stream=null;s.tools=new Map();s.rail=null;$('input').value='';$('send').disabled=true;appendUser(text);const r=await fetch(`/api/conversations/${encodeURIComponent(s.id)}/chat/stream`,{method:'POST',headers:{'content-type':'application/json','accept':'text/event-stream'},body:JSON.stringify({message:text,max_rounds:10})});await read(r);await pick(s.id);await load(false);s.busy=false;$('send').disabled=false}
async function create(){const c=await api('/api/conversations',{method:'POST',body:JSON.stringify({title:'live browser model proof'})});await load(false);await pick(c.id)}
$('new').onclick=()=>create().catch(e=>toast(e.message));$('send').onclick=()=>send().catch(e=>{s.busy=false;toast(e.message)});$('input').addEventListener('keydown',e=>{if(e.key==='Enter'&&!e.shiftKey){e.preventDefault();send().catch(x=>toast(x.message))}});load(true).catch(e=>toast(e.message));
</script>
</body>
</html>"##;
